mapper.select:
SELECT a.*
FROM ACHIEVEMENT a
LEFT JOIN USER_ACH_PROGRESS p ON a.ACHIEVEMENT_ID = p.ACHIEVEMENT_ID AND p.MEMBER_ID = #{memberId}
WHERE a.ACH_TYPE = #{achType}
AND (p.IS_ACHIEVED IS NULL OR p.IS_ACHIEVED = 'N')

mapper.update:
UPDATE USER_ACH_PROGRESS 
SET IS_ACHIEVED = 'Y' 
WHERE MEMBER_ID = #{memberId} AND ACHIEVEMENT_ID = #{achievementId}

UPDATE MEMBER 
SET EXP_POINT = NVL(EXP_POINT, 0) + #{expAmount}
WHERE MEMBER_ID = #{memberId}

UPDATE MEMBER 
SET TITLE_ID = #{titleId}
WHERE MEMBER_ID = #{memberId}
